create sequence attendances_seq start with 1 increment by 50;
create sequence grade_constant_seq start with 1 increment by 50;
create sequence grades_seq start with 1 increment by 50;
create sequence lesson_instances_seq start with 1 increment by 50;
create sequence schedule_lessons_seq start with 1 increment by 50;
create sequence school_classes_seq start with 1 increment by 50;
create sequence subjects_seq start with 1 increment by 50;
create sequence teaching_assignments_seq start with 1 increment by 50;
create table attendances (id bigint not null, lesson_instance_id bigint, student_id bigint, status varchar(255) check (status in ('ABSENT','LATE','EXCUSED')), primary key (id));
create table grade_constant (value integer, id bigint not null, description varchar(255), name varchar(255), primary key (id));
create table grades (value integer, created_at timestamp(6), id bigint not null, lesson_instance_id bigint not null, student_id bigint, updated_at timestamp(6), type varchar(255), primary key (id));
create table lesson_instances (lesson_date date not null, id bigint not null, schedule_lesson_id bigint not null, primary key (id), unique (schedule_lesson_id, lesson_date));
create table schedule_lessons (lesson_number integer not null, id bigint not null, teaching_assignment_id bigint not null, class_room varchar(255), day_of_week varchar(255) not null check (day_of_week in ('MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY','SUNDAY')), primary key (id), unique (teaching_assignment_id, day_of_week, lesson_number));
create table school_classes (class_teacher_id bigint, created_at timestamp(6), id bigint not null, updated_at timestamp(6), name varchar(255), year varchar(255), primary key (id));
create table subjects (created_at timestamp(6), id bigint not null, updated_at timestamp(6), name varchar(255) not null, primary key (id));
create table teaching_assignments (id bigint not null, school_class_id bigint not null, subject_id bigint not null, teacher_id bigint, primary key (id), unique (teacher_id, school_class_id, subject_id));
alter table if exists attendances add constraint FKa1svcnoc2degkd9c8kciwhpul foreign key (lesson_instance_id) references lesson_instances;
alter table if exists grades add constraint FKfrf84hk0kq9xo9695hdv7hom8 foreign key (lesson_instance_id) references lesson_instances;
alter table if exists lesson_instances add constraint FKa0h7tjvw9aae28h8ixq3c35qg foreign key (schedule_lesson_id) references schedule_lessons;
alter table if exists schedule_lessons add constraint FKhnpxkm03bvl7wyuiwog7ld1qa foreign key (teaching_assignment_id) references teaching_assignments;
alter table if exists teaching_assignments add constraint FK2j8g928cm3qhw83174j9gv0f8 foreign key (school_class_id) references school_classes;
alter table if exists teaching_assignments add constraint FK3xdxo1bu1pmp99lnjsgxh7foq foreign key (subject_id) references subjects;
create table parents (id bigint generated by default as identity, user_id bigint not null unique, primary key (id));
create table students (class_id bigint, id bigint generated by default as identity, user_id bigint not null unique, primary key (id));
create table teachers (id bigint generated by default as identity, user_id bigint not null unique, primary key (id));
create table users (created_at timestamp(6), id bigint generated by default as identity, updated_at timestamp(6), first_name varchar(255), keycloack_id varchar(255) not null unique, last_name varchar(255), primary key (id));
alter table if exists parents add constraint FKchh8tf8w072tapgqoijrahojk foreign key (user_id) references users;
alter table if exists students add constraint FKdt1cjx5ve5bdabmuuf3ibrwaq foreign key (user_id) references users;
alter table if exists teachers add constraint FKb8dct7w2j1vl1r2bpstw5isc0 foreign key (user_id) references users;
